      "brother_aldric_fen": {
        "name": "Bruder Aldric",
        "title": "Priester des Tals",
        "greeting": "Das Licht halte dich über Wasser, {playerName}. Die Toten in diesem Moor schlafen nicht: sie waten."
      },
